    public static function svg(string $name, string $class = ''): string
    {
        $ic = self::MAP[$name] ?? null;
        if ($ic === null) { return ''; }
        $cls = trim('inline-block align-[-0.125em] ' . $class);
        return '<svg class="' . e($cls) . '" style="width:1em;height:1em" viewBox="' . $ic[0]
            . '" fill="currentColor" aria-hidden="true" xmlns="http://www.w3.org/2000/svg">' . $ic[1] . '</svg>';
    }
}
